using Ledgerly.Application.Abstractions; using Ledgerly.Application.Bills; using Ledgerly.Application.Journals; using Ledgerly.Domain.Entities; using Ledgerly.Domain.Enums; using Ledgerly.Domain.ValueObjects; namespace Ledgerly.Application.Tests; public class BillServiceTests { static readonly Guid Org=Guid.NewGuid(); [Fact] public async Task ApproveAsync_posts_journal(){ var a=new InMemoryAccountRepository(); var j=new InMemoryJournalRepository(); var c=new InMemoryContactRepository(); var t=new InMemoryTaxCodeRepository(); var b=new InMemoryBillRepository(); var svc=new BillService(b,c,a,t,new JournalService(j,a)); var vendor=new Contact(Org,ContactType.Vendor,"Vendor Co",null,null,null,null,new CurrencyCode("USD"),PaymentTerms.Net30,null,Guid.NewGuid()); await c.AddAsync(vendor); var exp=new Account(Org,"5000","Exp",AccountType.Expense,new CurrencyCode("USD"),new Money(0m,new CurrencyCode("USD")),null); var ap=new Account(Org,"2100","AP",AccountType.Liability,new CurrencyCode("USD"),new Money(0m,new CurrencyCode("USD")),null); await a.AddAsync(exp); await a.AddAsync(ap); var bill=await svc.CreateAsync(new CreateBillRequest(Org,vendor.Id,"BILL-1",new DateOnly(2026,3,1),new DateOnly(2026,3,31),"USD",exp.Id,ap.Id)); await svc.AddLineAsync(Org,bill.Value!.Id,new AddBillLineRequest("Supplies",1m,200m,null,0m)); var approved=await svc.ApproveAsync(Org,bill.Value.Id); Assert.True(approved.IsSuccess); Assert.Equal(BillStatus.Approved,approved.Value!.Status);} sealed class InMemoryBillRepository:IBillRepository{List<Bill> _l=new(); public Task<Bill?> GetByIdAsync(Guid o,Guid id,CancellationToken ct=default)=>Task.FromResult(_l.FirstOrDefault(x=>x.OrganizationId==o&&x.Id==id)); public Task AddAsync(Bill bill,CancellationToken ct=default){_l.Add(bill);return Task.CompletedTask;} public Task UpdateAsync(Bill bill,CancellationToken ct=default)=>Task.CompletedTask;} sealed class InMemoryTaxCodeRepository:ITaxCodeRepository{List<TaxCode> _l=new(); public Task<TaxCode?> GetByIdAsync(Guid o,Guid id,CancellationToken ct=default)=>Task.FromResult(_l.FirstOrDefault(x=>x.OrganizationId==o&&x.Id==id)); public Task AddAsync(TaxCode t,CancellationToken ct=default){_l.Add(t);return Task.CompletedTask;}} sealed class InMemoryContactRepository:IContactRepository{List<Contact> _l=new(); public Task<Contact?> GetByIdAsync(Guid o,Guid id,CancellationToken ct=default)=>Task.FromResult(_l.FirstOrDefault(x=>x.OrganizationId==o&&x.Id==id)); public Task<IReadOnlyList<Contact>> ListByTypeAsync(Guid o,ContactType t,bool ia=false,CancellationToken ct=default)=>Task.FromResult<IReadOnlyList<Contact>>(_l.Where(x=>x.OrganizationId==o&&x.ContactType==t).ToList()); public Task AddAsync(Contact c,CancellationToken ct=default){_l.Add(c);return Task.CompletedTask;} public Task UpdateAsync(Contact c,CancellationToken ct=default)=>Task.CompletedTask;} sealed class InMemoryJournalRepository:IJournalRepository{List<JournalEntry> _l=new(); public Task<JournalEntry?> GetByIdAsync(Guid o,Guid id,CancellationToken ct=default)=>Task.FromResult(_l.FirstOrDefault(x=>x.OrganizationId==o&&x.Id==id)); public Task<IReadOnlyList<JournalEntry>> ListByOrganizationAsync(Guid o,CancellationToken ct=default)=>Task.FromResult<IReadOnlyList<JournalEntry>>(_l.Where(x=>x.OrganizationId==o).ToList()); public Task AddAsync(JournalEntry e,CancellationToken ct=default){_l.Add(e);return Task.CompletedTask;} public Task UpdateAsync(JournalEntry e,CancellationToken ct=default)=>Task.CompletedTask;} sealed class InMemoryAccountRepository:IAccountRepository{List<Account> _l=new(); public Task<Account?> GetByIdAsync(Guid o,Guid id,CancellationToken ct=default)=>Task.FromResult(_l.FirstOrDefault(x=>x.OrganizationId==o&&x.Id==id)); public Task<Account?> GetByCodeAsync(Guid o,string code,CancellationToken ct=default)=>Task.FromResult(_l.FirstOrDefault(x=>x.OrganizationId==o&&x.Code==code)); public Task<IReadOnlyList<Account>> ListByOrganizationAsync(Guid o,bool ia=false,CancellationToken ct=default)=>Task.FromResult<IReadOnlyList<Account>>(_l.Where(x=>x.OrganizationId==o).ToList()); public Task<IReadOnlyList<Account>> GetChildrenAsync(Guid o,Guid p,CancellationToken ct=default)=>Task.FromResult<IReadOnlyList<Account>>(Array.Empty<Account>()); public Task<bool> HasActiveChildrenAsync(Guid o,Guid id,CancellationToken ct=default)=>Task.FromResult(false); public Task AddAsync(Account a,CancellationToken ct=default){_l.Add(a);return Task.CompletedTask;} public Task UpdateAsync(Account a,CancellationToken ct=default)=>Task.CompletedTask;} }
